import { formatEGP } from "@/lib/money";

type PrintTicket = {
  id: string;
  total: number;
  note: string | null;
  createdAt: Date | string;
  cashierName?: string;
  items: {
    worker: { name: string };
    service: { title: string };
    priceSnapshot: number;
  }[];
};

const LOGO =
  "data:image/png;base64,";

export function printReceipt(ticket: PrintTicket) {
  const date = new Date(ticket.createdAt).toLocaleString("ar-EG", {
    dateStyle: "medium",
    timeStyle: "short",
  });

  const rows = ticket.items
    .map(
      (i) => `
      <tr>
        <td>${i.service.title}</td>
        <td class="price">${formatEGP(i.priceSnapshot)}</td>
      </tr>`,
    )
    .join("");

  const workerNames = [...new Set(ticket.items.map((i) => i.worker.name))].join(
    " / ",
  );

  const noteRow = ticket.note
    ? `<p class="note">ملاحظة: ${ticket.note}</p>`
    : "";

  const metaRows = [
    `<p class="meta">التاريخ: ${date}</p>`,
    `<p class="meta">رقم الإيصال: #${ticket.id.slice(-6).toUpperCase()}</p>`,
    ticket.cashierName
      ? `<p class="meta">الكاشير: ${ticket.cashierName}</p>`
      : "",
    `<p class="meta">العامل: ${workerNames}</p>`,
  ]
    .filter(Boolean)
    .join("");

  const html = `<!DOCTYPE html>
<html dir="rtl" lang="ar">
<head>
  <meta charset="UTF-8" />
  <title>إيصال رقم ${ticket.id.slice(-6).toUpperCase()}</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body {
      font-family: 'Tajawal', Tahoma, Arial, sans-serif;
      font-size: 12px;
      color: #111;
      padding: 4mm 6mm;
      width: 72mm;
      margin: 0 auto;
    }
    .brand {
      display: flex;
      flex-direction: column;
      align-items: center;
      margin-bottom: 6px;
    }
    .brand-logo {
      width: 64px;
      height: 64px;
      object-fit: contain;
      margin-bottom: 2px;
    }
    .shop-name-en {
      font-size: 9px;
      font-weight: 700;
      letter-spacing: 3px;
      color: #666;
      text-transform: uppercase;
      margin-bottom: 1px;
    }
    .shop-name {
      font-size: 18px;
      font-weight: 700;
    }
    .divider { border: none; border-top: 1px dashed #aaa; margin: 5px 0; }
    .meta { font-size: 11px; color: #444; margin-bottom: 2px; }
    table {
      width: 100%;
      border-collapse: collapse;
      margin: 5px 0;
      font-size: 11px;
    }
    th {
      text-align: right;
      border-bottom: 1px solid #ccc;
      padding: 3px 1px;
      font-size: 10px;
      color: #555;
    }
    td { padding: 3px 1px; vertical-align: top; }
    .price { text-align: left; white-space: nowrap; }
    th:last-child { text-align: left; }
    .total-row {
      display: flex;
      justify-content: space-between;
      font-weight: 700;
      font-size: 13px;
      padding: 5px 1px;
      border-top: 1px solid #ccc;
      margin-top: 3px;
    }
    .note { font-size: 10px; color: #555; margin-top: 3px; }
    .footer {
      text-align: center;
      font-size: 10px;
      color: #888;
      margin-top: 8px;
    }
    @media print {
      body { padding: 2mm 4mm; width: 72mm; }
    }
  </style>
</head>
<body>
  <div class="brand">
    <img src="${LOGO}" alt="fe5oo" class="brand-logo" />
    <div class="shop-name-en">Fe5oo</div>
  </div>
  <hr class="divider" />
  ${metaRows}
  <hr class="divider" />
  <table>
    <thead>
      <tr>
        <th>الخدمة</th>
        <th style="text-align:left">السعر</th>
      </tr>
    </thead>
    <tbody>${rows}</tbody>
  </table>
  <div class="total-row">
    <span>الإجمالي</span>
    <span>${formatEGP(ticket.total)}</span>
  </div>
  ${noteRow}
  <hr class="divider" />
  <div class="footer">شكراً لزيارتكم</div>
</body>
</html>`;

  const win = window.open("", "_blank", "width=360,height=620");
  if (!win) return;
  win.document.write(html);
  win.document.close();
  win.focus();
  win.print();
}
